export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input);
  if (!s) return "";
  // Normalize and remove combining diacritics
  const normalized = s.normalize && s.normalize("NFKD").replace(/[\u0300-\u036f]/g, "") || s;
  // Lowercase and replace non-alphanumerics with hyphen
  const slug = normalized.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
  return slug;
}

export function truncate(input, maxLen = 0, suffix = "…") {
  const s = toStr(input);
  if (!s) return "";
  if (!maxLen || maxLen >= s.length) return s;
  if (maxLen <= suffix.length) return suffix.slice(0, maxLen);
  const cut = maxLen - suffix.length;
  let head = s.slice(0, cut);
  const lastSpace = head.lastIndexOf(' ');
  if (lastSpace > -1) {
    // avoid producing empty result
    const candidate = head.slice(0, lastSpace);
    if (candidate.length > 0) head = candidate;
  }
  return head + suffix;
}

export function camelCase(input) {
  const words = splitWords(input);
  if (!words.length) return "";
  const first = words[0].toLowerCase();
  const rest = words.slice(1).map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join('');
  return first + rest;
}

export function kebabCase(input) {
  let s = toStr(input);
  if (!s) return "";
  // Break camelCase boundaries: fooBar -> foo-Bar
  s = s.replace(/([a-z0-9])([A-Z])/g, "$1-$2");
  const words = splitWords(s);
  return words.map(w => w.toLowerCase()).join('-');
}

export function titleCase(input) {
  const words = splitWords(input);
  return words.map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (!s) return "";
  if (!width || width < 1) return s;
  const words = s.split(/\s+/);
  const lines = [];
  let current = '';
  for (const word of words) {
    if (!current) {
      if (word.length > width) {
        // long single word on its own line
        lines.push(word);
      } else {
        current = word;
      }
    } else {
      if ((current.length + 1 + word.length) <= width) {
        current = current + ' ' + word;
      } else {
        lines.push(current);
        if (word.length > width) {
          lines.push(word);
          current = '';
        } else {
          current = word;
        }
      }
    }
  }
  if (current) lines.push(current);
  return lines.join('\n');
}

export function stripHtml(input) {
  let s = toStr(input);
  if (!s) return "";
  // Remove scripts/styles
  s = s.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
  s = s.replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, '');
  // Remove tags
  s = s.replace(/<[^>]+>/g, '');
  // Decode some common entities
  const entities = {
    amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' '
  };
  s = s.replace(/&([a-zA-Z]+);/g, (m, name) => (entities[name.toLowerCase()] ?? m));
  s = s.replace(/&#(\d+);/g, (m, n) => String.fromCharCode(Number(n)));
  s = s.replace(/&#x([0-9a-fA-F]+);/g, (m, n) => String.fromCharCode(parseInt(n, 16)));
  return s;
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = toStr(input);
  if (!s) return "";
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) return s + 'es';
  if (/[aeiou]y$/i.test(lower)) return s + 's';
  if (/y$/i.test(lower)) return s.slice(0, -1) + 'ies';
  if (lower.endsWith('fe')) return s.slice(0, -2) + 'ves';
  if (lower.endsWith('f')) return s.slice(0, -1) + 'ves';
  return s + 's';
}

export function levenshtein(a, b) {
  const s = Array.from(toStr(a));
  const t = Array.from(toStr(b));
  const n = s.length;
  const m = t.length;
  if (n === 0) return m;
  if (m === 0) return n;
  const v0 = new Array(m + 1).fill(0);
  const v1 = new Array(m + 1).fill(0);
  for (let j = 0; j <= m; j++) v0[j] = j;
  for (let i = 0; i < n; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < m; j++) {
      const cost = s[i] === t[j] ? 0 : 1;
      v1[j + 1] = Math.min(
        v1[j] + 1,       // insertion
        v0[j + 1] + 1,   // deletion
        v0[j] + cost     // substitution
      );
    }
    for (let j = 0; j <= m; j++) v0[j] = v1[j];
  }
  return v1[m];
}
